ATTRIBUTE.VALUE:
delete from WC_PBCS_BUDGET_ACTUALS_F  where PERIOD in(
select distinct PERIOD from WC_PBCS_BUDGET_ACTUALS_FS);

commit;

MERGE INTO WC_PBCS_BUDGET_ACTUALS_F e
    USING (select ROW_WID, substr(ORG_NAME,0,4) AS LE from W_INT_ORG_D where LEGAL_ENTITY_FLG = 'Y' and ROW_WID <> 0) h
    ON (substr(e.LEGAL_ENTITY,4,4)  = h.LE)
  WHEN MATCHED THEN
    UPDATE SET e.LEGAL_ENTITY_WID = h.ROW_WID;
    
commit;

UPDATE PROD_PA_BIDATA32.WC_AZ_BATCH_CTR_D SET REFRESH_INDICATOR = 0 WHERE TABLE_NAME IN ('WC_PBCS_BUDGET_ACTUALS_PRMPT_F','WC_PBCS_BUDGET_ACTUALS_GANDA_F');
commit;

DROP TABLE WC_PBCS_BUDGET_ACTUALS_PRMPT_F;

CREATE TABLE WC_PBCS_BUDGET_ACTUALS_PRMPT_F AS
  (SELECT DISTINCT GL_PERIOD_WID,
      PU_WID,
      CURRENCY,
      AUDITTRAIL,
      LEGAL_ENTITY
    FROM WC_PBCS_BUDGET_ACTUALS_F
  );

DROP TABLE WC_PBCS_BUDGET_ACTUALS_GANDA_F;

CREATE TABLE WC_PBCS_BUDGET_ACTUALS_GANDA_F  AS 
  (SELECT F.* FROM WC_PBCS_BUDGET_ACTUALS_F F, WC_BU_ORG_DH DH, WC_ACCOUNT_DH ADH WHERE F.PU_WID=DH.ROW_WID
AND ADH.ROW_WID=F.GL_ACCOUNT_WID AND DH.OPEN_FLG='Y' AND 
F.AUDITTRAIL IN ('Management_View','Statutory_View') AND DH.X_DEPT_NAME='IT' AND CURRENCY='USD_Reporting' AND (ADH.ACCOUNT_NUM LIKE '5%' OR ADH.ACCOUNT_NUM LIKE '6%' OR ADH.ACCOUNT_NUM LIKE '7%'));

grant select on PROD_PA_BIDATA32.WC_PBCS_BUDGET_ACTUALS_PRMPT_F to PROD_AZ_USER;
grant select on PROD_PA_BIDATA32.WC_PBCS_BUDGET_ACTUALS_GANDA_F to PROD_AZ_USER;
UPDATE PROD_PA_BIDATA32.WC_AZ_BATCH_CTR_D SET  REFRESH_INDICATOR = 1,LAST_REFRESH_DATE = SYSDATE  WHERE TABLE_NAME in ('WC_PBCS_BUDGET_ACTUALS_PRMPT_F','WC_PBCS_BUDGET_ACTUALS_GANDA_F');
commit;

Drop table WC_PBCS_PLAN_FX_RT_TMP;
Commit;
Create table WC_PBCS_PLAN_FX_RT_TMP as (
select currency, PERIOD,ROW_WID,FX_RATE from WC_PBCS_PLAN_EX_RATE_D where FX_RATE_TYPE='FX Rates - Average'
UNION
select 'USD_Reporting' currency, PERIOD,ROW_WID,FX_RATE from WC_PBCS_PLAN_EX_RATE_D where FX_RATE_TYPE='FX Rates - Average'
AND currency='USD')
;
Commit;


Drop table WC_PBCS_BA_PROMPT_ADHOC_F;
Commit;

CREATE TABLE WC_PBCS_BA_PROMPT_ADHOC_F AS (
SELECT DISTINCT AUDITTRAIL,'USD_Reporting' CURRENCY,'LE-071-USD' LEGAL_ENTITY,'Consolidated Actuals' SCENARIO
FROM WC_PBCS_BUDGET_ACTUALS_F
UNION
SELECT DISTINCT AUDITTRAIL,'USD_Reporting' CURRENCY,'LE-071-USD' LEGAL_ENTITY,'Consolidated Budget' SCENARIO
FROM WC_PBCS_BUDGET_ACTUALS_F
UNION
SELECT DISTINCT AUDITTRAIL,CURRENCY,LEGAL_ENTITY,'Ledger Actuals' SCENARIO FROM WC_PBCS_BUDGET_ACTUALS_F
UNION
SELECT DISTINCT AUDITTRAIL,CURRENCY,LEGAL_ENTITY,'Ledger Budget' SCENARIO FROM WC_PBCS_BUDGET_ACTUALS_F);

Commit;

CALL  PROC_PCBS_ADHOC_PS();
